INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_connectivity_rate', '连通率', 'Connectivity Rate', 'mid_war', '系统性能', '实际连通节点数 / 总节点数 × 100%', 'records_military_operation_info', NULL, 'custom', 'SELECT (total_node_count - isolated_node_count) * 100.0 / NULLIF(total_node_count, 0) FROM records_military_operation_info WHERE operation_id = {operation_id}', '%', 'positive', 6, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_deception_success_rate', '欺骗信号成功率', 'Deception Success Rate', 'mid_war', '通信进攻操作', '欺骗成功次数 / 欺骗总次数 × 100%', 'records_comm_attack_operation', 'spoofing_success', 'percentage', 'WHERE operation_type = \'spoofing_signal\'', '%', 'positive', 10, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_emergency_handling', '应急处理', 'Emergency Response', 'mid_war', '系统性能', '作战过程中，操作员感知到异常并做出反应的平均时间', 'records_military_communication_info', 'operator_reaction_ms', 'avg', NULL, 'ms', 'negative', 2, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_emergency_restoration', '应急抢通', 'Emergency Restoration', 'mid_war', '通信保障操作', '链路中断后启动应急手段并恢复通信的平均耗时（仅统计成功的抢通）', 'records_link_maintenance_events', 'recovery_duration_ms', 'avg_conditional', 'recovery_success = 1 AND recovery_duration_ms IS NOT NULL', 'ms', 'negative', 5, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_jamming_target_time', '干扰目标锁定耗时', 'Jamming Target Lock Time', 'mid_war', '通信进攻操作', '从发起干扰锁定到锁定完成的平均耗时', 'records_comm_attack_operation', NULL, 'custom', 'SELECT AVG(end_time_ms - start_time_ms) FROM records_comm_attack_operation WHERE operation_id = {operation_id} AND operation_type = \'jamming_target_lock\' AND end_time_ms IS NOT NULL', 'ms', 'negative', 9, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_link_maintenance', '链路维持', 'Link Maintenance', 'mid_war', '通信保障操作', '通信链路维持能力 = (总通信时长 - 总中断时长) / 总通信时长 × 100%', NULL, NULL, 'custom', 'SELECT ((SELECT MAX(end_time_ms)-MIN(start_time_ms) FROM records_military_communication_info WHERE operation_id = {operation_id}) - COALESCE((SELECT SUM(interruption_end_ms-interruption_start_ms) FROM records_link_maintenance_events WHERE operation_id = {operation_id}), 0)) * 100.0 / NULLIF((SELECT MAX(end_time_ms)-MIN(start_time_ms) FROM records_military_communication_info WHERE operation_id = {operation_id}), 0)', '%', 'positive', 3, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_mission_reliability', '任务可靠度', 'Mission Reliability', 'mid_war', '系统性能', '通信成功次数 / 总通信次数 × 100%', 'records_military_communication_info', 'comm_success', 'percentage', NULL, '%', 'positive', 7, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_network_setup_time', '组网时长', 'Network Setup Time', 'pre_war', '系统性能', '战前系统开设阶段，从指令发出到所有节点就绪的平均时长', 'records_military_operation_info', 'avg_network_setup_time_ms', 'avg', NULL, 'ms', 'negative', 1, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_rework_rate', '返修率', 'Rework Rate', 'post_war', '维修与反馈', '维修失败次数 / 需要维修的总次数 × 100%', 'records_link_maintenance_events', NULL, 'custom', 'SELECT COUNT(CASE WHEN maintenance_success = 0 AND maintenance_required = 1 THEN 1 END) * 100.0 / NULLIF(COUNT(CASE WHEN maintenance_required = 1 THEN 1 END), 0) FROM records_link_maintenance_events WHERE operation_id = {operation_id}', '%', 'negative', 8, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
INSERT INTO `equipment_qt_indicator_def` VALUES ('eqt_service_activation', '业务开通', 'Service Activation', 'mid_war', '通信保障操作', '从发起通信请求到通信建立完成的平均时长', 'records_military_communication_info', 'call_setup_ms', 'avg', NULL, 'ms', 'negative', 4, 1, NULL, '2026-04-08 19:01:13', '2026-04-08 19:01:13');
