INSERT INTO `evaluation_grade_definition` VALUES (12, 'D-', '差-', '差', 30.00, 39.00, '[30,39)', 12, '差-：表现很差，严重不达标', '2026-04-07 14:44:56');
INSERT INTO `evaluation_grade_definition` VALUES (13, 'E+', '极差+', '极差', 20.00, 30.00, '[20,30)', 13, '极差+：表现极差，几乎无法接受', '2026-04-07 14:44:56');
