DROP TABLE IF EXISTS `cost_evaluation_batch`;
CREATE TABLE `cost_evaluation_batch`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `evaluation_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '评估批次ID',
  `batch_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '批次名称（可选）',
  `evaluation_time` datetime NOT NULL COMMENT '评估时间',
  `weight_method` enum('equal','ahp','manual') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'equal' COMMENT '权重确定方法：等权/AHP/手动',
  `normalization_method` enum('minmax','zscore','manual') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'minmax' COMMENT '归一化方法',
  `active_indicators` json NULL COMMENT '启用的指标列表（JSON数组）',
  `operation_ids` json NULL COMMENT '本次评估参评的作战ID列表（JSON数组）',
  `global_min_values` json NULL COMMENT '全局最小值快照 { indicator_key: min_value }',
  `global_max_values` json NULL COMMENT '全局最大值快照 { indicator_key: max_value }',
  `status` enum('pending','computing','completed','failed') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'pending' COMMENT '批次状态',
  `operation_count` int NULL DEFAULT 0 COMMENT '该批次作战任务数量',
  `completed_count` int NULL DEFAULT 0 COMMENT '已完成评估数量',
  `avg_cost_index` decimal(8, 6) NULL DEFAULT NULL COMMENT '批次平均成本指数 C（所有作战均值，归一化到 0~1）',
  `avg_effectiveness_score` decimal(10, 6) NULL DEFAULT NULL COMMENT '批次平均效能得分 E',
  `avg_cost_effectiveness_ratio` decimal(12, 6) NULL DEFAULT NULL COMMENT '批次平均效费比 R = E/C',
  `min_cost_index` decimal(8, 6) NULL DEFAULT NULL COMMENT '成本指数最小值',
  `max_cost_index` decimal(8, 6) NULL DEFAULT NULL COMMENT '成本指数最大值',
  `min_cost_effectiveness_ratio` decimal(12, 6) NULL DEFAULT NULL COMMENT '效费比最小值',
  `max_cost_effectiveness_ratio` decimal(12, 6) NULL DEFAULT NULL COMMENT '效费比最大值',
  `category_summary` json NULL COMMENT '各类成本汇总（批次整体各维度加权成本占比）',
  `weights_config` json NULL COMMENT '本次评估使用的权重配置快照',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '备注',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_evaluation_id`(`evaluation_id` ASC) USING BTREE,
  INDEX `idx_evaluation_time`(`evaluation_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '成本评估批次配置表' ROW_FORMAT = DYNAMIC;

