-- ----------------------------
-- Table structure for cost_evaluation_record
-- ----------------------------
DROP TABLE IF EXISTS `cost_evaluation_record`;
CREATE TABLE `cost_evaluation_record`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `evaluation_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '评估批次ID',
  `operation_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '作战任务ID',
  `cost_index` decimal(8, 6) NULL DEFAULT NULL COMMENT '综合成本指数 C（归一化加权求和后，0~1）',
  `cost_index_raw` decimal(15, 4) NULL DEFAULT NULL COMMENT '原始成本指数（加权求和前，未归一化）',
  `effectiveness_score` decimal(10, 6) NULL DEFAULT NULL COMMENT '效能得分 E（来自惩罚模型最终得分）',
  `cost_effectiveness_ratio` decimal(12, 6) NULL DEFAULT NULL COMMENT '效费比 R = E/C',
  `cost_by_category` json NULL COMMENT '各类成本汇总 { \"人力\": 0.15, \"装备\": 0.20, ... }',
  `raw_indicators` json NULL COMMENT '原始指标数据 { \"cost_personnel_total\": 12000, ... }',
  `normalized_indicators` json NULL COMMENT '归一化后指标数据 { \"cost_personnel_total\": 0.45, ... }',
  `effective_normalized` json NULL COMMENT '方向调整后的成本分量（效益型已反向，0~1）',
  `weights_snapshot` json NULL COMMENT '权重快照 { \"cost_personnel_total\": 0.15, ... }',
  `normalization_bounds` json NULL COMMENT '归一化边界快照 { min: {...}, max: {...} }',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '备注',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_eval_operation`(`evaluation_id` ASC, `operation_id` ASC) USING BTREE,
  INDEX `idx_evaluation_id`(`evaluation_id` ASC) USING BTREE,
  INDEX `idx_operation_id`(`operation_id` ASC) USING BTREE,
  INDEX `idx_cost_index`(`cost_index` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 34 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '成本评估记录表（存储每次评估的成本数据）' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of cost_evaluation_record
-- ----------------------------

-- ----------------------------
-- Table structure for cost_indicator_config
-- ----------------------------
DROP TABLE IF EXISTS `cost_indicator_config`;
CREATE TABLE `cost_indicator_config`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `indicator_key` varchar(80) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '指标唯一标识（如 cost_personnel_total）',
  `indicator_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '指标中文名称',
  `indicator_name_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '指标英文名称（可选）',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '指标大类（人力/装备/能源/备件物流/训练/基础设施）',
  `sub_category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '指标子类（可选）',
  `indicator_type` enum('cost','benefit') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '指标类型：cost=成本型(越大成本越高), benefit=效益型(越大成本越低)',
  `source_table` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '数据来源表名（NULL表示手动输入）',
  `source_field` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '数据来源字段名',
  `source_expression` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '数据来源表达式（复杂计算时使用，如多个字段求和）',
  `normalization_min` decimal(15, 4) NULL DEFAULT NULL COMMENT '归一化下限ck,min',
  `normalization_max` decimal(15, 4) NULL DEFAULT NULL COMMENT '归一化上限ck,max',
  `use_actual_range` tinyint(1) NULL DEFAULT 1 COMMENT '是否使用实际数据范围作为归一化边界（1=是，0=使用固定值）',
  `weight` decimal(8, 6) NULL DEFAULT NULL COMMENT '该指标在成本指数中的权重（0~1）',
  `is_active` tinyint(1) NULL DEFAULT 1 COMMENT '是否启用（1=启用，0=禁用）',
  `sort_order` int NULL DEFAULT 0 COMMENT '排序序号',
  `unit` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '计量单位',
  `unit_abbrev` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '单位简称',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '指标说明',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '备注',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_indicator_key`(`indicator_key` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_is_active`(`is_active` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 16 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '成本指标配置表（定义指标元数据，支持动态扩展）' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of cost_indicator_config
-- ----------------------------

