  INDEX `idx_indicator`(`indicator_key` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 67 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '专家定性指标集结结果（质心分）' ROW_FORMAT = Dynamic;

