-- ----------------------------
-- Table structure for evaluation_grade_definition
-- ----------------------------
DROP TABLE IF EXISTS `evaluation_grade_definition`;
CREATE TABLE `evaluation_grade_definition`  (
  `grade_id` int NOT NULL AUTO_INCREMENT COMMENT '等级ID',
  `grade_code` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '等级代码：A+, A, A-, B+, B, B-, C+, C, C-, D+, D, D-, E+, E, E-',
  `grade_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '等级名称：优+, 优, 优-, 良+, 良, 良-, 合格+, 合格, 合格-, 差+, 差, 差-, 极差+, 极差, 极差-',
  `category` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '大类：优/良/合格/差/极差',
  `min_score` decimal(5, 2) NOT NULL COMMENT '最低分（包含）',
  `max_score` decimal(5, 2) NOT NULL COMMENT '最高分（不包含，最高等级除外）',
  `score_range` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '分数区间描述：[95,100], [90,95)等',
  `grade_level` int NOT NULL COMMENT '等级排序：1-15，数字越小等级越高',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '等级描述',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`grade_id`) USING BTREE,
  UNIQUE INDEX `grade_code`(`grade_code` ASC) USING BTREE,
  INDEX `idx_grade_code`(`grade_code` ASC) USING BTREE,
  INDEX `idx_category`(`category` ASC) USING BTREE,
  INDEX `idx_grade_level`(`grade_level` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 16 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '评分等级定义表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of evaluation_grade_definition
-- ----------------------------

-- ----------------------------
-- Table structure for expert_ahp_comparison_score
-- ----------------------------
DROP TABLE IF EXISTS `expert_ahp_comparison_score`;
CREATE TABLE `expert_ahp_comparison_score`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `expert_id` int NOT NULL COMMENT '专家id\r\n',
  `expert_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '专家名称',
  `comparison_key` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '比较对标识，如:安全性_可靠性',
  `score` decimal(5, 2) NOT NULL COMMENT '打分值(1-9标度)',
  `confidence` decimal(3, 2) NULL DEFAULT 0.80 COMMENT '把握度(0-1)',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5244 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '专家AHP原始打分表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of expert_ahp_comparison_score
-- ----------------------------

-- ----------------------------
-- Table structure for expert_ahp_group_weights
-- ----------------------------
DROP TABLE IF EXISTS `expert_ahp_group_weights`;
CREATE TABLE `expert_ahp_group_weights`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `group_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '专家组ID（UUID）',
  `expert_ids` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '专家ID集合（排序后逗号分隔），唯一标识',
  `expert_count` int NULL DEFAULT NULL COMMENT '专家数量',
  `group_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '专家组名称',
  `updated_at` datetime NULL DEFAULT NULL,
  `cross_domain_score` decimal(10, 6) NULL DEFAULT NULL COMMENT '域间 Saaty 标度 a（效能相对装备）',
  `cross_domain_confidence` decimal(3, 2) NULL DEFAULT NULL COMMENT '域间把握度',
  `eff_domain_weight` decimal(10, 6) NULL DEFAULT NULL COMMENT '域间：效能体系全局权重 w_eff=a/(1+a)',
  `eq_domain_weight` decimal(10, 6) NULL DEFAULT NULL COMMENT '域间：装备体系全局权重 w_eq=1/(1+a)',
  `eff_dim_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '效能维度层权重 JSON {dimName: weight}',
  `eff_dim_count` int NULL DEFAULT NULL COMMENT '效能维度数量',
  `eff_leaf_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '效能叶子指标全局权重 JSON Array of {dim,indicator,globalWeight}',
  `eff_leaf_count` int NULL DEFAULT NULL COMMENT '效能叶子指标数量',
  `eff_cr` decimal(8, 6) NULL DEFAULT NULL COMMENT '效能维度层 CR',
  `eq_dim_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '装备维度层权重 JSON {dimName: weight}',
  `eq_dim_count` int NULL DEFAULT NULL COMMENT '装备维度数量',
  `eq_leaf_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '装备叶子指标全局权重 JSON Array of {dim,indicator,globalWeight}',
  `eq_leaf_count` int NULL DEFAULT NULL COMMENT '装备叶子指标数量',
  `eq_cr_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '装备各层 CR JSON',
  `expert_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '专家权重明细 JSON（可信度信息）',
  `aggregated_unified_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '集结后完整统一快照 JSON（参照 AhpIndividualResult）',
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_expert_ids`(`expert_ids` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '专家集结 AHP 统一层次权重快照（效能+装备完整展开）' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of expert_ahp_group_weights
-- ----------------------------

-- ----------------------------
-- Table structure for expert_ahp_individual_weights
-- ----------------------------
DROP TABLE IF EXISTS `expert_ahp_individual_weights`;
CREATE TABLE `expert_ahp_individual_weights`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `expert_id` bigint NOT NULL,
  `expert_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  `eff_domain_weight` decimal(10, 6) NULL DEFAULT NULL COMMENT '域间：效能体系全局权重 w_eff=a/(1+a)',
  `eq_domain_weight` decimal(10, 6) NULL DEFAULT NULL COMMENT '域间：装备体系全局权重 w_eq=1/(1+a)',
  `cross_domain_score` decimal(10, 6) NULL DEFAULT NULL COMMENT '域间 Saaty 标度 a（效能相对装备）',
  `cross_domain_confidence` decimal(3, 2) NULL DEFAULT NULL COMMENT '域间把握度 λ',
  `eff_dim_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '效能维度层权重 JSON {dimName: weight}',
  `eff_dim_count` int NULL DEFAULT NULL COMMENT '效能维度数量',
  `eff_leaf_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '效能叶子指标全局权重 JSON Array of {dim,indicator,globalWeight}',
  `eff_leaf_count` int NULL DEFAULT NULL COMMENT '效能叶子指标数量',
  `eq_dim_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '装备维度层权重 JSON {dimName: weight}',
  `eq_dim_count` int NULL DEFAULT NULL COMMENT '装备维度数量',
  `eq_leaf_weights_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '装备叶子指标全局权重 JSON Array of {dim,indicator,globalWeight}',
  `eq_leaf_count` int NULL DEFAULT NULL COMMENT '装备叶子指标数量',
  `eff_cr` decimal(8, 6) NULL DEFAULT NULL COMMENT '效能维度层 CR',
  `eq_cr_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '装备各层 CR 及效能指标层 CR JSON',
  `ahp_result_json` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '完整 AHP 统一计算结果 JSON',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_expert_id`(`expert_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '专家AHP层次总排序权重快照（效能+装备统一展开，所有叶子全局权重之和=1）' ROW_FORMAT = DYNAMIC;

