-- ----------------------------
-- Table structure for penalty_model_result
-- ----------------------------
DROP TABLE IF EXISTS `penalty_model_result`;
CREATE TABLE `penalty_model_result`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `evaluation_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '评估批次ID',
  `operation_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '作战任务ID',
  `original_score` decimal(10, 6) NOT NULL COMMENT '集结综合得分（原始，Sstage）',
  `overall_penalty` decimal(8, 6) NOT NULL COMMENT '综合惩罚因子 P = min(F1..Fn)',
  `final_score` decimal(10, 6) NOT NULL COMMENT '最终效能得分 Sfinal = Sstage × P',
  `penalty_amplitude` decimal(8, 6) NOT NULL COMMENT '惩罚幅度 (Sstage - Sfinal) / Sstage',
  `penalty_details` json NOT NULL COMMENT '各指标惩罚因子详情（JSON）',
  `batch_avg_score_map` json NULL COMMENT '各指标批次算术平均分 { indicator_key: avg_score（0~1） }',
  `batch_min_score_map` json NULL COMMENT '各指标批次最低分   { indicator_key: min_score（0~1） }',
  `batch_avg_fi_map` json NULL COMMENT '各指标 Fi（均值口径）{ indicator_key: fi }',
  `batch_min_fi_map` json NULL COMMENT '各指标 Fi（批次最低分口径）{ indicator_key: fi }',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_evaluation_operation`(`evaluation_id` ASC, `operation_id` ASC) USING BTREE,
  INDEX `idx_evaluation_id`(`evaluation_id` ASC) USING BTREE,
  INDEX `idx_operation_id`(`operation_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '惩罚模型计算结果表（每作战一条记录）' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Records of penalty_model_result
-- ----------------------------

-- ----------------------------
-- Table structure for records_comm_attack_operation
-- ----------------------------
DROP TABLE IF EXISTS `records_comm_attack_operation`;
CREATE TABLE `records_comm_attack_operation`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `operation_id` int NOT NULL COMMENT '作战ID',
  `operation_type` enum('jamming_target_lock','jamming_effect','spoofing_signal') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '操作类型',
  `start_time_ms` bigint NOT NULL COMMENT '操作开始时间戳',
  `end_time_ms` bigint NULL DEFAULT NULL COMMENT '操作结束时间戳',
  `operator_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '操作员ID',
  `target_node` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '目标节点',
  `target_communication_id` bigint NULL DEFAULT NULL COMMENT '关联通信记录ID',
  `jamming_power_dbm` decimal(8, 2) NULL DEFAULT NULL COMMENT '干扰功率dBm',
  `jamming_frequency_hz` decimal(15, 2) NULL DEFAULT NULL COMMENT '干扰频率Hz',
  `effect_assessment` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '干扰效能评估文本',
  `spoofing_signal_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '欺骗信号类型',
  `spoofing_success` tinyint(1) NULL DEFAULT NULL COMMENT '欺骗是否成功',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_operation`(`operation_id` ASC) USING BTREE,
  INDEX `idx_type`(`operation_type` ASC) USING BTREE,
  INDEX `idx_time`(`start_time_ms` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 362 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '进攻操作记录表' ROW_FORMAT = Dynamic;

