-- ----------------------------
-- Table structure for records_comm_defense_operation
-- ----------------------------
DROP TABLE IF EXISTS `records_comm_defense_operation`;
CREATE TABLE `records_comm_defense_operation`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `operation_id` int NOT NULL COMMENT '作战ID',
  `operation_type` enum('detection_awareness','anti_jamming','anti_deception') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '操作类型',
  `start_time_ms` bigint NOT NULL COMMENT '操作开始时间戳',
  `end_time_ms` bigint NULL DEFAULT NULL COMMENT '操作结束时间戳',
  `operator_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '操作员ID',
  `detection_time_ms` bigint NULL DEFAULT NULL COMMENT '感知异常时间ms',
  `detection_method` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '发现手段',
  `jamming_detected` tinyint(1) NULL DEFAULT NULL COMMENT '是否检测到干扰',
  `anti_jamming_actions` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '抗干扰措施',
  `anti_jamming_success` tinyint(1) NULL DEFAULT NULL COMMENT '抗干扰是否成功',
  `suspicious_signal_detected` tinyint(1) NULL DEFAULT NULL COMMENT '是否发现可疑信号',
  `verification_method` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '核实方式',
  `verification_result` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '核实结果',
  `notes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_operation`(`operation_id` ASC) USING BTREE,
  INDEX `idx_type`(`operation_type` ASC) USING BTREE,
  INDEX `idx_time`(`start_time_ms` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 354 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '防御操作记录表' ROW_FORMAT = Dynamic;

